"use client";

import { useState } from "react";
import CodeBlock from "@/components/ui/CodeBlock";

const steps = [
  {
    id: "install",
    title: "Install",
    description: "使用 pip 安装 HiClaw",
    code: `$ pip install hiclaw`,
  },
  {
    id: "init",
    title: "Initialize",
    description: "初始化配置文件和 Matrix 连接",
    code: `$ hiclaw init
# 按提示配置 Matrix Homeserver 地址
# 输入访问令牌或创建新账户`,
  },
  {
    id: "run",
    title: "Run",
    description: "启动 Agent 团队执行任务",
    code: `$ hiclaw run --task "分析这份季度报告并生成摘要"
# Manager Agent 将自动分解任务
# Worker Agents 并行执行
# 你可以在 Matrix 客户端实时观察`,
  },
];

export default function QuickStartSection() {
  const [activeStep, setActiveStep] = useState(0);

  return (
    <section id="quickstart" className="section-padding bg-white">
      <div className="section-container">
        {/* Section Header */}
        <div className="mx-auto mb-12 max-w-2xl text-center md:mb-16">
          <h2 className="mb-4 text-3xl font-bold text-text-primary md:text-4xl">
            Quick Start
          </h2>
          <p className="text-lg text-text-secondary">
            三步开始使用 HiClaw，体验多 Agent 协作的强大能力
          </p>
        </div>

        {/* Steps */}
        <div className="mx-auto max-w-3xl">
          {/* Step Tabs */}
          <div className="mb-8 flex gap-2 overflow-x-auto pb-2">
            {steps.map((step, index) => (
              <button
                key={step.id}
                onClick={() => setActiveStep(index)}
                className={`flex items-center gap-2 whitespace-nowrap rounded-lg px-4 py-2 text-sm font-medium transition-all ${
                  activeStep === index
                    ? "bg-primary-600 text-white"
                    : "bg-slate-100 text-text-secondary hover:bg-slate-200"
                }`}
              >
                <span
                  className={`flex h-6 w-6 items-center justify-center rounded-full text-xs ${
                    activeStep === index
                      ? "bg-white/20 text-white"
                      : "bg-slate-200 text-slate-600"
                  }`}
                >
                  {index + 1}
                </span>
                <span>{step.title}</span>
              </button>
            ))}
          </div>

          {/* Step Content */}
          <div className="space-y-4">
            <p className="text-text-secondary">{steps[activeStep].description}</p>
            <CodeBlock code={steps[activeStep].code} language="bash" />
          </div>

          {/* All Steps Preview */}
          <div className="mt-12 rounded-xl border border-slate-200 bg-surface-muted p-6">
            <h3 className="mb-4 font-semibold text-text-primary">
              Complete Example
            </h3>
            <CodeBlock
              code={`# 1. Install HiClaw
$ pip install hiclaw

# 2. Initialize configuration
$ hiclaw init

# 3. Run your first task
$ hiclaw run --task "Research the latest AI trends and create a summary report"

# Output:
# [Manager] Task received, analyzing...
# [Manager] Created subtasks: research, analysis, writing
# [Worker-1] Starting research task...
# [Worker-2] Preparing analysis framework...
# [Worker-3] Ready for summary writing...
# 
# You can now open your Matrix client to observe the conversation!`}
              language="bash"
              showLineNumbers
            />
          </div>
        </div>
      </div>
    </section>
  );
}
